using Microsoft.EntityFrameworkCore; using Microsoft.Extensions.Configuration; using Microsoft.Extensions.DependencyInjection; using ModularMonolith.Modules.Orders.Application; using ModularMonolith.Modules.Orders.Infrastructure; namespace ModularMonolith.Modules.Orders;
public static class OrdersModule{ public static IMvcBuilder AddOrdersModule(this IMvcBuilder mvc,IConfiguration cfg){mvc.Services.AddDbContext<OrdersDbContext>(o=>o.UseSqlite(cfg.GetConnectionString("Orders")??"Data Source=modular-monolith.db")); mvc.Services.AddScoped<OrdersService>(); mvc.AddApplicationPart(typeof(OrdersModule).Assembly); return mvc;} public static async Task EnsureOrdersDatabaseAsync(this IServiceProvider sp){using var s=sp.CreateScope(); await s.ServiceProvider.GetRequiredService<OrdersDbContext>().Database.EnsureCreatedAsync();}}
